@page "/admin/users"
@rendermode InteractiveServer
@attribute [Authorize(Roles = "Admin")]
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@using sv_5ab987e353d343e28c7d75c1df3c5ec7.Data

@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Manage all users and their assigned roles.</p>

@if (userRoles is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var entry in userRoles)
            {
                <tr>
                    <td>@entry.Email</td>
                    <td>@string.Join(", ", entry.Roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<UserWithRoles>? userRoles;

    protected override async Task OnInitializedAsync()
    {
        var users = UserManager.Users.ToList();
        userRoles = new List<UserWithRoles>();

        foreach (var user in users)
        {
            var roles = await UserManager.GetRolesAsync(user);
            userRoles.Add(new UserWithRoles(user.Email!, roles));
        }
    }

    private record UserWithRoles(string Email, IList<string> Roles);
}

@inject NavigationManager Navigation

@code {
    protected override void OnInitialized()
    {
        Navigation.NavigateTo($"Account/Login?ReturnUrl={Uri.EscapeDataString(Navigation.Uri)}", forceLoad: true);
    }
}

